// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and prevent SSRF attacks
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Reject if URL contains user info (credentials)
	if parsedURL.User != nil {
		ctx.Error("URL must not contain credentials", fasthttp.StatusBadRequest)
		return
	}

	// Strict scheme validation - only http and https allowed
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Validate hostname to prevent SSRF to internal networks
	if parsedURL.Hostname() == "" {
		ctx.Error("URL must have a valid hostname", fasthttp.StatusBadRequest)
		return
	}

	// Block private IP ranges and localhost to prevent SSRF
	host := parsedURL.Hostname()
	if isPrivateHost(host) {
		ctx.Error("URL resolves to a private or internal address", fasthttp.StatusBadRequest)
		return
	}

	// Re-encode the URL to prevent injection attacks
	targetURL = parsedURL.String()

	// Use fasthttp.Client with security-focused configuration
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		// Disable automatic redirects to prevent open redirect vulnerabilities
		// We'll handle redirects manually with validation
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Limit response body size to prevent memory exhaustion attacks
	maxBodySize := 5 * 1024 * 1024 // 5MB max

