	redirectCount := 0
	maxRedirects := 3
	for isRedirectStatusCode(res.StatusCode()) && redirectCount < maxRedirects {
		redirectCount++

		location := res.Header.Peek("Location")
		if len(location) == 0 {
			ctx.Error("Redirect location missing", fasthttp.StatusBadGateway)
			return
		}

		// Parse the location URL
		locationURL, err := url.Parse(string(location))
		if err != nil {
			ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
			return
		}

		// Resolve relative URLs
		redirectURL := parsedURL.ResolveReference(locationURL)

		// Validate redirect URL scheme
		if redirectURL.Scheme != "http" && redirectURL.Scheme != "https" {
			ctx.Error("Redirect to non-http(s) scheme not allowed", fasthttp.StatusBadGateway)
			return
