// isRedirectStatusCode checks if status code indicates a redirect
func isRedirectStatusCode(code int) bool {
	return code == 301 || code == 302 || code == 303 || code == 307 || code == 308
}

// isPrivateHost checks if a hostname resolves to a private/internal IP address
func isPrivateHost(host string) bool {
	// Check for localhost variations
	lowerHost := strings.ToLower(host)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" ||
		strings.HasPrefix(lowerHost, "127.") || lowerHost == "0.0.0.0" || lowerHost == "::" {
		return true
	}

	// Check for IPv6 loopback
	if host == "[::1]" || host == "[::]" {
		return true
	}

	// Check for private IPv4 ranges using simple prefix matching
	// Note: This is a basic check; production code should use proper IP parsing
	privatePrefixes := []string{
		"10.",     // 10.0.0.0/8
		"172.16.", // 172.16.0.0/12 start
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
		"172.25.",
		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.", // 172.31.255.255 end
		"192.168.", // 192.168.0.0/16
		"169.254.", // Link-local
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(host, prefix) {
			return true
		}
	}

	// Check for IPv6 unique local addresses (fc00::/7)
	if strings.HasPrefix(host, "fc") || strings.HasPrefix(host, "fd") {
		return true
	}

	// Check for IPv6 link-local (fe80::/10)
	if strings.HasPrefix(host, "fe80:") {
		return true
	}

	return false
}

