	// Fetch URL with redirects
	err := client.DoRedirects(fastReq, fastResp, 10)
	if err != nil {
		resp := Response{Error: "failed to fetch URL: " + err.Error()}
		sendJSON(ctx, resp, fasthttp.StatusInternalServerError)
		return
	}

	// Read body
	body := fastResp.Body()

	// Parse HTML to extract title and description
	title, description := parseHTML(string(body))

	resp := Response{
		Title:       title,
		Description: description,
	}
	sendJSON(ctx, resp, fasthttp.StatusOK)
}

func sendJSON(ctx *fasthttp.RequestCtx, resp Response, statusCode int) {
	ctx.SetStatusCode(statusCode)
	data, _ := json.Marshal(resp)
	ctx.Write(data) // nolint:errcheck
}

func parseHTML(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				lowerName := strings.ToLower(name)
				if lowerName == "description" || lowerName == "og:description" {
					if description == "" || lowerName == "og:description" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

