// isPrivateIP checks if the given hostname resolves to a private/internal IP address
func isPrivateIP(hostname string) bool {
	// Remove port if present
	if idx := strings.LastIndex(hostname, ":"); idx != -1 {
		hostname = hostname[:idx]
	}

	// Handle IPv6 zone identifiers
	if idx := strings.Index(hostname, "%"); idx != -1 {
		hostname = hostname[:idx]
	}

	// Remove brackets from IPv6 addresses
	hostname = strings.Trim(hostname, "[]")

	// Check for localhost and common internal names
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || lowerHost == "localhost.localdomain" {
		return true
	}

	// Check for private IP ranges directly without DNS resolution first
	ip := net.ParseIP(hostname)
	if ip != nil {
		// Check loopback
		if ip.IsLoopback() {
			return true
		}
		// Check private ranges
		if ip.IsPrivate() {
			return true
		}
		// Check link-local
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
		// Check multicast
		if ip.IsMulticast() {
			return true
		}
		// Check unspecified
		if ip.IsUnspecified() {
			return true
		}
		return false
	}

	// For hostnames that are not valid IP addresses, we need to check if they resolve to private IPs
	// But we must avoid infinite recursion - only do DNS lookup for actual hostnames, not IPs
	// Since we've already checked if it's a valid IP above, this is a hostname

	// Additional check: don't do DNS lookup for things that look like IPs but failed parsing
	// (e.g., malformed IPs) - treat them as safe to avoid issues
	if strings.Count(hostname, ".") > 0 || strings.Contains(hostname, ":") {
		// Try to resolve hostname to check if it points to private IP
		addrs, err := net.LookupIP(hostname)
		if err != nil {
			// If we can't resolve, assume it's safe but this could be a DNS rebinding risk
			// In production, you might want to reject unresolvable hosts
			return false
		}

		for _, addr := range addrs {
			// Check each resolved IP directly without recursive call
			if addr.IsLoopback() {
				return true
			}
			if addr.IsPrivate() {
				return true
			}
			if addr.IsLinkLocalUnicast() || addr.IsLinkLocalMulticast() {
				return true
			}
			if addr.IsMulticast() {
				return true
			}
			if addr.IsUnspecified() {
				return true
			}
		}
	}

	return false
}

