// Request represents the incoming JSON request
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response
type Response struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		resp := Response{Error: "invalid JSON body"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		resp := Response{Error: "url field is required"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Create request with timeout
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Set timeout using context or deadline
	deadline := time.Now().Add(3 * time.Second)

	// Use DoDeadline with max redirects of 10
	err := client.DoDeadline(fastReq, fastResp, deadline)
	if err != nil {
		resp := Response{Error: "failed to fetch URL: " + err.Error()}
		sendJSON(ctx, resp, fasthttp.StatusInternalServerError)
		return
	}

	// Read body
	body := fastResp.Body()

	// Parse HTML to extract title and description
	title, description := parseHTML(string(body))

	resp := Response{
		Title:       title,
		Description: description,
	}
	sendJSON(ctx, resp, fasthttp.StatusOK)
}

func sendJSON(ctx *fasthttp.RequestCtx, data interface{}, statusCode int) {
	ctx.SetStatusCode(statusCode)
	jsonData, _ := json.Marshal(data)
	ctx.Write(jsonData)
}

func parseHTML(htmlStr string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlStr))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				lowerName := strings.ToLower(name)
				if lowerName == "description" || lowerName == "og:description" {
					if description == "" || lowerName == "og:description" {
						description = content
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, strings.TrimSpace(description)
}

func main() {
	server := &fasthttp.Server{
		Handler: FetchURLPreview,
	}

	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

