// isPrivateIP checks if the given hostname/IP is in a private range
func isPrivateIP(hostname string) bool {
	// Check for localhost variants
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" ||
		strings.HasPrefix(lowerHost, "127.") {
		return true
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve, treat as potentially dangerous
		// But allow through if it looks like a valid public domain
		// This is a conservative approach - you might want to be stricter
		return false
	}

	for _, ip := range ips {
		// Check IPv4 private ranges
		ip4 := ip.To4()
		if ip4 != nil {
			// 10.0.0.0/8
			if ip4[0] == 10 {
				return true
			}
			// 172.16.0.0/12
			if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
				return true
			}
			// 192.168.0.0/16
			if ip4[0] == 192 && ip4[1] == 168 {
				return true
			}
			// 169.254.0.0/16 (link-local)
			if ip4[0] == 169 && ip4[1] == 254 {
				return true
			}
			// 127.0.0.0/8 (loopback)
			if ip4[0] == 127 {
				return true
			}
			// 0.0.0.0/8
			if ip4[0] == 0 {
				return true
			}
		}

		// Check IPv6 private ranges
		// ::1/128 (loopback)
		if ip.IsLoopback() {
			return true
		}
		// fe80::/10 (link-local)
		// fc00::/7 (unique local)
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
		// Check for unique local addresses (fc00::/7)
		if len(ip) == 16 {
			if ip[0]&0xfe == 0xfc {
				return true
			}
		}
	}

	return false
}

