func parseHTMLWithTimeout(body []byte, timeout time.Duration) (title, description string, err error) {
	done := make(chan struct{})
	var t, d string
	var e error

	go func() {
		defer close(done)
		t, d, e = parseHTML(strings.NewReader(string(body)))
	}()

	select {
	case <-done:
