		"224.0.0.0/4",
		"240.0.0.0/4",
		"255.255.255.255/32",
	}

	for _, cidr := range privateRanges {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}

	return false
}

func validateURL(inputURL string) error {
	parsedURL, err := url.Parse(inputURL)
	if err != nil {
		return err
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return io.EOF
	}

	// Check for empty host
	if parsedURL.Hostname() == "" {
		return io.EOF
	}

	// Resolve hostname to IP addresses
	host := parsedURL.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return err
	}

	// Check if any resolved IP is private
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return io.EOF
		}
	}

	return nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		resp := Response{Error: "invalid JSON body"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		resp := Response{Error: "url field is required"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL to prevent SSRF
	if err := validateURL(req.URL); err != nil {
		resp := Response{Error: "invalid or blocked URL"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Create fasthttp request and response
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

