		return true
	}

	// Check for private IPv4 ranges
	// 10.0.0.0/8
	if strings.HasPrefix(hostname, "10.") {
		return true
	}
	// 172.16.0.0/12
	if strings.HasPrefix(hostname, "172.") {
		parts := strings.Split(hostname, ".")
		if len(parts) >= 2 {
			secondOctet := 0
			fmt.Sscanf(parts[1], "%d", &secondOctet)
			if secondOctet >= 16 && secondOctet <= 31 {
				return true
			}
		}
	}
	// 192.168.0.0/16
	if strings.HasPrefix(hostname, "192.168.") {
		return true
	}
	// 169.254.0.0/16 (link-local)
	if strings.HasPrefix(hostname, "169.254.") {
		return true
	}
	// 0.0.0.0/8
	if hostname == "0.0.0.0" || strings.HasPrefix(hostname, "0.") {
		return true
	}

	// Check for IPv6 unique local addresses (fc00::/7)
	if strings.HasPrefix(hostname, "fc") || strings.HasPrefix(hostname, "fd") {
		// Simple check for hex pattern
		if len(hostname) >= 2 {
			return true
		}
	}
	// IPv6 link-local (fe80::/10)
	if strings.HasPrefix(hostname, "fe8") || strings.HasPrefix(hostname, "fe9") ||
		strings.HasPrefix(hostname, "fea") || strings.HasPrefix(hostname, "feb") {
