package main

import (
	"encoding/json"
	"io"
	"net"
	"net/url"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// RequestBody represents the incoming JSON request body
type RequestBody struct {
	URL string `json:"url"`
}

// ResponseBody represents the JSON response
type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		filteredAddr, err := filterAddr(addr)
		if err != nil {
			return nil, err
		}
		return fasthttp.DialDualStack(filteredAddr)
	},
}

// filterAddr checks if the address is safe to connect to (SSRF protection)
func filterAddr(addr string) (string, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		// Try without port
		host = addr
		port = "80"
	}

	// Parse IP to check for private ranges
	ip := net.ParseIP(host)
	if ip == nil {
		// It's a hostname, resolve it
		ips, err := net.LookupIP(host)
		if err != nil {
			return "", err
		}
		if len(ips) == 0 {
			return "", err
		}
		ip = ips[0]
	}

	// Check for private IP ranges
	if isPrivateIP(ip) {
		return "", err
	}

	// Reconstruct address
	if port != "" && port != "80" && port != "443" {
		return net.JoinHostPort(host, port), nil
	}
	return host, nil
}

// isPrivateIP checks if an IP is in a private range
func isPrivateIP(ip net.IP) bool {
	privateRanges := []string{
		"127.0.0.0/8",    // Loopback
		"10.0.0.0/8",     // Private
		"172.16.0.0/12",  // Private
		"192.168.0.0/16", // Private
		"169.254.0.0/16", // Link-local
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // IPv6 unique local
		"fe80::/10",      // IPv6 link-local
		"0.0.0.0/8",      // Current network
		"::ffff:127.0.0.0/104", // IPv4-mapped loopback
	}

	for _, cidr := range privateRanges {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		resp := ResponseBody{Error: "invalid JSON body"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if reqBody.URL == "" {
		resp := ResponseBody{Error: "url field is required"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and host
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		resp := ResponseBody{Error: "invalid URL"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		resp := ResponseBody{Error: "only http and https URLs are allowed"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Host == "" {
		resp := ResponseBody{Error: "URL must have a host"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
