	const maxBodySize = 5 * 1024 * 1024 // 5 MB limit
	bodyBytes := res.Body()
	if len(bodyBytes) > maxBodySize {
		ctx.Error("Response too large", fasthttp.StatusBadGateway)
		return
	}

	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isPrivateHost checks if a hostname resolves to a private/internal IP address
// or is a known internal hostname pattern
func isPrivateHost(hostname string) bool {
	hostname = strings.ToLower(strings.TrimSpace(hostname))

	// Check for empty hostname
	if hostname == "" {
		return true
	}

	// Check for localhost variations
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || hostname == "0:0:0:0:0:0:0:1" {
		return true
	}

	// Check for IPv6 localhost
	if strings.HasPrefix(hostname, "[::1]") || hostname == "[::1]" {
		return true
	}

	// Check for IPv4 loopback (127.x.x.x)
	if strings.HasPrefix(hostname, "127.") {
		return true
	}

	// Check for zero IP
	if hostname == "0.0.0.0" || hostname == "[::]" || hostname == "::" {
		return true
	}

	// Check for private IPv4 ranges
	// 10.0.0.0/8
	if strings.HasPrefix(hostname, "10.") {
		return true
	}
	// 172.16.0.0/12
	if strings.HasPrefix(hostname, "172.") {
		parts := strings.Split(hostname, ".")
		if len(parts) >= 2 {
			secondOctet := 0
			fmt.Sscanf(parts[1], "%d", &secondOctet)
			if secondOctet >= 16 && secondOctet <= 31 {
				return true
			}
		}
	}
	// 192.168.0.0/16
	if strings.HasPrefix(hostname, "192.168.") {
		return true
	}
	// 169.254.0.0/16 (link-local)
	if strings.HasPrefix(hostname, "169.254.") {
		return true
	}

	// Check for IPv6 unique local addresses (fc00::/7)
	if strings.HasPrefix(hostname, "fc") || strings.HasPrefix(hostname, "fd") {
		// Simple check for IPv6 ULA prefix
		if len(hostname) >= 2 {
			return true
		}
	}

	// Check for IPv6 link-local (fe80::/10)
	if strings.HasPrefix(hostname, "fe8") || strings.HasPrefix(hostname, "fe9") ||
		strings.HasPrefix(hostname, "fea") || strings.HasPrefix(hostname, "feb") {
		return true
	}

	// Check for common internal domain patterns
	internalPatterns := []string{
		".internal",
		".local",
		".localhost",
		".intranet",
		".private",
		".corp",
		".home",
		".lan",
	}
	for _, pattern := range internalPatterns {
		if strings.HasSuffix(hostname, pattern) {
			return true
		}
	}

	return false
}

