func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		resp := Response{Error: "invalid JSON body"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		resp := Response{Error: "url field is required"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Create request with timeout
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Set timeout using context-like approach with goroutine and channel
	done := make(chan error, 1)
	go func() {
		done <- client.DoRedirects(fastReq, fastResp, 10)
	}()

	select {
	case err := <-done:
		if err != nil {
			resp := Response{Error: "failed to fetch URL: " + err.Error()}
			sendJSON(ctx, resp, fasthttp.StatusInternalServerError)
			return
		}
	case <-time.After(3 * time.Second):
		resp := Response{Error: "request timeout"}
		sendJSON(ctx, resp, fasthttp.StatusGatewayTimeout)
		return
	}

	// Read response body
	body := fastResp.Body()

	// Parse HTML to extract title and description
	title, description := parseHTML(string(body))

	resp := Response{
		Title:       title,
		Description: description,
	}
	sendJSON(ctx, resp, fasthttp.StatusOK)
}

func sendJSON(ctx *fasthttp.RequestCtx, resp Response, statusCode int) {
	ctx.SetStatusCode(statusCode)
	data, _ := json.Marshal(resp)
	ctx.Write(data)
}

func parseHTML(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.ToLower(name) == "description" || name == "og:description" {
					if description == "" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func main() {
	server := &fasthttp.Server{
		Handler: FetchURLPreview,
	}

	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

