		"169.254.0.0/16",
		"0.0.0.0/8",
		"::1/128",
	}

	for _, cidr := range privateRanges {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}

	return false
}

// resolveAndCheckHost resolves hostname and checks if it points to private IP.
func resolveAndCheckHost(host string) error {
	// Check for IPv4 literal with port
	hostWithoutPort, _, err := net.SplitHostPort(host)
	if err != nil {
		hostWithoutPort = host
	}

	// Try to parse as IP directly
	ip := net.ParseIP(hostWithoutPort)
	if ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("private IP addresses are not allowed")
		}
		return nil
	}

	// It's a hostname, resolve it
	ips, err := net.LookupIP(hostWithoutPort)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	for _, resolvedIP := range ips {
		if isPrivateIP(resolvedIP) {
			return fmt.Errorf("hostname resolves to private IP address")
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Check for SSRF - block private/internal IPs
	if err := resolveAndCheckHost(parsedURL.Host); err != nil {
		ctx.Error(fmt.Sprintf("SSRF protection: %v", err), fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client with custom dial function to prevent DNS rebinding
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Parse the address
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				host = addr
				if parsedURL.Scheme == "https" {
					port = "443"
				} else {
					port = "80"
				}
			}

			// Re-check the resolved IP at connection time to prevent DNS rebinding
			ips, err := net.LookupIP(host)
			if err != nil {
