// isPrivateHost checks if the hostname is a private/internal address
func isPrivateHost(hostname string) bool {
	hostname = strings.ToLower(strings.TrimSpace(hostname))

	// Check for localhost variations
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || hostname == "0:0:0:0:0:0:0:1" {
		return true
	}

	// Check for IPv6 loopback
	if strings.HasPrefix(hostname, "[::1]") || strings.HasPrefix(hostname, "[0:0:0:0:0:0:0:1]") {
		return true
	}

	// Resolve hostname to IP and check if it's private
	// This prevents DNS rebinding attacks where a hostname resolves to a private IP
	ips, err := net.LookupIP(hostname)
	if err == nil {
		for _, ip := range ips {
			if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
				return true
			}
			// Check for unique local addresses (fc00::/7)
			if ip.To4() == nil && len(ip) == 16 {
				if ip[0]&0xfe == 0xfc {
					return true
				}
			}
		}
	}

	// Check for IPv4 private ranges by direct string matching (fallback)
	if strings.HasPrefix(hostname, "10.") ||
		strings.HasPrefix(hostname, "192.168.") ||
		strings.HasPrefix(hostname, "172.") {
		// More precise check for 172.16.0.0/12
		if strings.HasPrefix(hostname, "172.") {
			parts := strings.Split(hostname, ".")
			if len(parts) >= 2 {
				secondOctet := 0
				fmt.Sscanf(parts[1], "%d", &secondOctet)
				if secondOctet >= 16 && secondOctet <= 31 {
					return true
				}
			}
		} else {
			return true
		}
	}

	// Check for link-local addresses
	if strings.HasPrefix(hostname, "169.254.") {
		return true
	}

	// Check for IPv6 unique local addresses (fc00::/7)
	if strings.HasPrefix(hostname, "fc") || strings.HasPrefix(hostname, "fd") {
		return true
	}

	// Check for IPv6 link-local addresses (fe80::/10)
	if strings.HasPrefix(hostname, "fe80:") {
		return true
	}

	// Check for empty or invalid hostnames
	if hostname == "" {
		return true
	}

	return false
}

