// RequestBody represents the incoming JSON request body
type RequestBody struct {
	URL string `json:"url"`
}

// ResponseBody represents the JSON response
type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		return fasthttp.DialDualStack(filterAddr(addr))
	},
	ReadTimeout:  5 * time.Second,
	WriteTimeout: 5 * time.Second,
	MaxConnDuration: 10 * time.Second,
}

// filterAddr blocks private IP addresses to prevent SSRF
func filterAddr(addr string) string {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		// Try without port
		host = addr
		port = ""
	}

	// Remove brackets from IPv6 addresses
	host = strings.Trim(host, "[]")

	ip := net.ParseIP(host)
	if ip != nil {
		// Check if IP is private
		if isPrivateIP(ip) {
			return "127.0.0.1:1" // Return invalid address to cause connection failure
		}
		return addr
	}

	// For hostnames, resolve and check
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	var r net.Resolver
	ips, err := r.LookupIP(ctx, "ip", host)
	if err != nil {
		return addr
	}

	for _, resolvedIP := range ips {
		if isPrivateIP(resolvedIP) {
			return "127.0.0.1:1" // Return invalid address to cause connection failure
		}
	}

	if port != "" {
		return net.JoinHostPort(host, port)
	}
	return host
}

// isPrivateIP checks if an IP address is private/reserved
func isPrivateIP(ip net.IP) bool {
	// Check for loopback, link-local, private ranges
	privateRanges := []string{
		"127.0.0.0/8",    // Loopback
		"10.0.0.0/8",     // Private
		"172.16.0.0/12",  // Private
		"192.168.0.0/16", // Private
		"169.254.0.0/16", // Link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	}

	for _, cidr := range privateRanges {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}

	return false
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		resp := ResponseBody{Error: "invalid JSON body"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if reqBody.URL == "" {
		resp := ResponseBody{Error: "url field is required"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme to prevent file:// and other dangerous schemes
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		resp := ResponseBody{Error: "invalid URL"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		resp := ResponseBody{Error: "only http and https URLs are allowed"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Prepare response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Execute request with redirects and timeout
	if err := client.DoRedirects(req, resp, 3); err != nil {
		respBody := ResponseBody{Error: "failed to fetch URL: " + err.Error()}
		sendJSONResponse(ctx, respBody, fasthttp.StatusInternalServerError)
		return
	}

	// Read response body
	body := resp.Body()

	// Parse HTML to extract title and description
	title, description := parseHTML(string(body))

	response := ResponseBody{
		Title:       title,
		Description: description,
	}
	sendJSONResponse(ctx, response, fasthttp.StatusOK)
}

func sendJSONResponse(ctx *fasthttp.RequestCtx, data ResponseBody, statusCode int) {
	ctx.SetStatusCode(statusCode)
	jsonData, _ := json.Marshal(data)
	ctx.Write(jsonData)
}

func parseHTML(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name", "property":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" || name == "og:description" {
					if description == "" || name == "og:description" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

