		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and prevent SSRF attacks
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Strict scheme validation - only allow http and https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Security: Reject URLs with credentials (user:password@host)
	if parsedURL.User != nil {
		ctx.Error("URL must not contain credentials", fasthttp.StatusBadRequest)
		return
	}

	// Security: Validate host is present and not empty
	if parsedURL.Host == "" {
		ctx.Error("URL must have a valid host", fasthttp.StatusBadRequest)
		return
	}

	// Security: Reject localhost and private IP addresses to prevent SSRF
	host := strings.ToLower(parsedURL.Hostname())
	if isPrivateHost(host) {
		ctx.Error("Access to this host is not allowed", fasthttp.StatusForbidden)
		return
	}

	// Reconstruct clean URL to prevent injection attacks
	cleanURL := fmt.Sprintf("%s://%s%s", parsedURL.Scheme, parsedURL.Host, parsedURL.Path)
	if parsedURL.RawQuery != "" {
		cleanURL = cleanURL + "?" + parsedURL.RawQuery
	}
	if parsedURL.Fragment != "" {
		cleanURL = cleanURL + "#" + parsedURL.Fragment
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		// Security: Limit response body size to prevent memory exhaustion
		MaxResponseBodySize: 5 * 1024 * 1024, // 5MB max
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(cleanURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 3 // Reduced from 10 for security
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Security: Check Content-Type to ensure we're parsing HTML
	contentType := string(res.Header.ContentType())
	if !isValidContentType(contentType) {
		ctx.Error("Invalid content type: expected HTML", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Security: Additional size check after response
	const maxBodySize = 5 * 1024 * 1024 // 5MB
	if len(bodyBytes) > maxBodySize {
		ctx.Error("Response body too large", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isPrivateHost checks if the host is localhost or a private IP address
func isPrivateHost(host string) bool {
	host = strings.ToLower(host)

	// Check for localhost variations
	if host == "localhost" || host == "127.0.0.1" || host == "::1" || host == "0.0.0.0" {
		return true
	}

	// Check for IPv6 loopback
	if strings.HasPrefix(host, "[::1]") || host == "[::]" {
		return true
	}

	// Check for IPv4 loopback (127.x.x.x)
	if strings.HasPrefix(host, "127.") {
		return true
	}

	// Check for private IPv4 ranges
	// 10.0.0.0/8
	if strings.HasPrefix(host, "10.") {
		return true
	}
	// 172.16.0.0/12
	if strings.HasPrefix(host, "172.") {
		parts := strings.Split(host, ".")
		if len(parts) >= 2 {
			secondOctet := 0
			fmt.Sscanf(parts[1], "%d", &secondOctet)
			if secondOctet >= 16 && secondOctet <= 31 {
				return true
			}
		}
	}
	// 192.168.0.0/16
	if strings.HasPrefix(host, "192.168.") {
		return true
	}
	// 169.254.0.0/16 (link-local)
	if strings.HasPrefix(host, "169.254.") {
		return true
	}

	// Check for IPv6 private ranges
	// fc00::/7 (unique local addresses)
	if strings.HasPrefix(host, "fc") || strings.HasPrefix(host, "fd") {
		return true
	}
	// fe80::/10 (link-local)
	if strings.HasPrefix(host, "fe80:") {
		return true
	}

	return false
}

// isValidContentType checks if the content type is valid HTML
func isValidContentType(contentType string) bool {
	contentType = strings.ToLower(contentType)
	// Allow text/html and application/xhtml+xml
	return strings.Contains(contentType, "text/html") ||
		strings.Contains(contentType, "application/xhtml")
}

