	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		resp := ResponseBody{Error: "invalid JSON body"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if reqBody.URL == "" {
		resp := ResponseBody{Error: "url field is required"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL to prevent SSRF
	if !isValidURL(reqBody.URL) {
		resp := ResponseBody{Error: "invalid or forbidden URL"}
		sendJSONResponse(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Prepare request with timeout context
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Prepare response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Execute request with redirects and timeout
	clientWithTimeout := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialDualStack(filterAddr(addr))
		},
		ReadTimeout:     5 * time.Second,
		WriteTimeout:    5 * time.Second,
		MaxConnDuration: 10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
	}

	// Execute request with redirects
	if err := clientWithTimeout.DoRedirects(req, resp, 3); err != nil {
		respBody := ResponseBody{Error: "failed to fetch URL: " + err.Error()}
		sendJSONResponse(ctx, respBody, fasthttp.StatusInternalServerError)
		return
	}

	// Read response body with size limit
	body := resp.Body()

	// Limit body size to prevent memory issues
	const maxBodySize = 1024 * 1024 // 1MB
	if len(body) > maxBodySize {
		body = body[:maxBodySize]
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(body)

	respBody := ResponseBody{
		Title:       title,
		Description: description,
	}
	sendJSONResponse(ctx, respBody, fasthttp.StatusOK)
}

func sendJSONResponse(ctx *fasthttp.RequestCtx, data ResponseBody, statusCode int) {
	ctx.SetStatusCode(statusCode)
	jsonData, _ := json.Marshal(data)
	ctx.Write(jsonData)
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = strings.TrimSpace(n.FirstChild.Data)
		}
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "name", "property":
					name = attr.Val
				case "content":
					content = attr.Val
				}
			}
			if name == "description" || name == "og:description" {
				if description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func main() {
	// Example server setup for testing
	// In production, this would be configured with proper routing
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	server := &fasthttp.Server{
		Handler: requestHandler,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	// Run server on :8080
	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

