)

// Request represents the incoming JSON request
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response
type Response struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
	ReadTimeout: 3 * time.Second,
	WriteTimeout: 3 * time.Second,
	MaxConnWaitTimeout: 3 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		resp := Response{Error: "invalid JSON body"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		resp := Response{Error: "url field is required"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Create request with timeout
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Use DoRedirects with max redirects of 10 and timeout
	err := client.DoRedirects(fastReq, fastResp, 10)
	if err != nil {
		// Check if it's a timeout error
		if strings.Contains(err.Error(), "timeout") || strings.Contains(err.Error(), "deadline exceeded") || strings.Contains(err.Error(), "i/o timeout") {
			resp := Response{Error: "request timeout"}
			sendJSON(ctx, resp, fasthttp.StatusGatewayTimeout)
			return
		}
		resp := Response{Error: "failed to fetch URL: " + err.Error()}
		sendJSON(ctx, resp, fasthttp.StatusBadGateway)
		return
	}

	// Read body with size limit for safety
	body := fastResp.Body()

	// Parse HTML
	title, description := parseHTML(string(body))

	resp := Response{
		Title:       title,
		Description: description,
	}

	sendJSON(ctx, resp, fasthttp.StatusOK)
}

func sendJSON(ctx *fasthttp.RequestCtx, v interface{}, statusCode int) {
	ctx.SetStatusCode(statusCode)
	data, _ := json.Marshal(v)
	ctx.Write(data)
}

func parseHTML(htmlStr string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlStr))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				lowerName := strings.ToLower(name)
				if lowerName == "description" || lowerName == "og:description" {
					if description == "" || lowerName == "og:description" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

