// filterAddr checks if the address is safe to connect to (SSRF protection)
func filterAddr(addr string) (string, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		// Try without port
		host = addr
		port = ""
	}

	// Parse as URL to extract hostname if needed
	if u, err := url.Parse(host); err == nil && u.Hostname() != "" {
		host = u.Hostname()
	}

	// Resolve the host to check for private IPs
